section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/opportunity-solution-trees.json",
  "title": "Opportunity Solution Trees",
  "type": "object",
  "required": [
    "artefact_id",
    "outcome",
    "opportunities",
    "solutions",
    "experiments",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "outcome": {
      "type": "string",
      "description": "single measurable product outcome at the root",
      "minLength": 1
    },
    "opportunities": {
      "type": "array",
      "description": "customer pain/desire nodes anchored to evidence",
      "minItems": 1
    },
    "solutions": {
      "type": "array",
      "description": "candidate solutions linked to opportunities",
      "minItems": 1
    },
    "experiments": {
      "type": "array",
      "description": "next-step tests to validate solutions",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
